mapper.select:
/* adm-master-application-sql-oracle.xml - selectDupApplicationCount */
SELECT
	count(1)
FROM
	TADMIN_MST_AP

AND APKEY = #{apkey}

mapper.insert:
		/* adm-master-application-sql-oracle.xml - insertApplication */
		INSERT INTO TADMIN_MST_AP (
			  APKEY
		    , APNM
		    , ISOFFLINE
		    , INSERTDATE
			, INSERTURKEY
   		  	, UPDATEDATE
			, UPDATEURKEY
		) VALUES (
			  #{apkey}
			, #{apnm}
   			, #{isoffline}
			, #{sysdate}
			, #{surkey}
			, #{sysdate}
			, #{surkey}
		)

mapper.update:
/* adm-master-application-sql-oracle.xml - updateApplication */
UPDATE
    TADMIN_MST_AP
SET
	  APNM = #{apnm}
	, ISOFFLINE = #{isoffline}
	, UPDATEDATE = #{sysdate}
	, UPDATEURKEY = #{surkey}

	AND APKEY = #{apkey}

mapper.delete:
/* adm-master-application-sql-oracle.xml - deleteApplication */
DELETE
FROM
    TADMIN_MST_AP

	AND APKEY = #{apkey}
